import{_ as t,o,c as i,ae as a}from"./chunks/framework.BD9pLfSD.js";const u=JSON.parse('{"title":"Light zkCompression Integration for xb77_gateway (Local Sources)","description":"","frontmatter":{},"headers":[],"relativePath":"docs/research/2026-01-17-light-compressed-state-integration.md","filePath":"docs/research/2026-01-17-light-compressed-state-integration.md"}'),r={name:"docs/research/2026-01-17-light-compressed-state-integration.md"};function s(d,e,c,n,l,p){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="light-zkcompression-integration-for-xb77-gateway-local-sources" tabindex="-1">Light zkCompression Integration for xb77_gateway (Local Sources) <a class="header-anchor" href="#light-zkcompression-integration-for-xb77-gateway-local-sources" aria-label="Permalink to &quot;Light zkCompression Integration for xb77_gateway (Local Sources)&quot;">​</a></h1><h2 id="executive-summary" tabindex="-1">Executive summary <a class="header-anchor" href="#executive-summary" aria-label="Permalink to &quot;Executive summary&quot;">​</a></h2><p>This report summarizes how to integrate Light Protocol&#39;s zkCompression compressed state into the <code>xb77_gateway</code> flow based on local sources <code>light_basics.txt</code> and <code>light_example.txt</code>. The core requirement is to use Light&#39;s Rust SDK (<code>light-sdk</code>) to create or update compressed accounts via CPI to the Light System Program using client-provided validity proofs and compressed account metadata. The recommended integration is: keep the gateway as the main program, add a Light-compressed receipt state update in <code>ResolvePrivateOrder</code>, and only introduce a separate escrow program if you need independent ownership, settlement logic, or third-party composition that must be isolated from the gateway program.</p><h2 id="key-findings" tabindex="-1">Key findings <a class="header-anchor" href="#key-findings" aria-label="Permalink to &quot;Key findings&quot;">​</a></h2><h3 id="_1-light-compressed-state-is-updated-via-cpi-with-client-supplied-proofs-and-metas" tabindex="-1">1) Light compressed state is updated via CPI with client-supplied proofs and metas <a class="header-anchor" href="#_1-light-compressed-state-is-updated-via-cpi-with-client-supplied-proofs-and-metas" aria-label="Permalink to &quot;1) Light compressed state is updated via CPI with client-supplied proofs and metas&quot;">​</a></h3><ul><li>Compressed accounts are stored off-chain; only hashes and Merkle tree updates are on-chain.</li><li>Updates follow a UTXO-style flow: consume old hash, produce new hash; no in-place overwrite.</li><li>Programs create/update compressed state via CPI to the Light System Program, providing: <ul><li><code>ValidityProof</code> (client fetched)</li><li><code>CompressedAccountMeta</code> (tree + index + address metadata)</li><li>Light System Program + Account Compression Program + state tree accounts (passed in remaining accounts)</li></ul></li></ul><p>Evidence: <code>light_basics.txt</code> (sections “On-Chain Program Development” and “Update a Compressed Account”), <code>light_example.txt</code> (native Rust example: <code>LightSystemProgramCpi::new_cpi(...).with_light_account(...).invoke(...)</code>).</p><h3 id="_2-light-sdk-primitives-used-in-rust-programs" tabindex="-1">2) Light SDK primitives used in Rust programs <a class="header-anchor" href="#_2-light-sdk-primitives-used-in-rust-programs" aria-label="Permalink to &quot;2) Light SDK primitives used in Rust programs&quot;">​</a></h3><ul><li><code>LightAccount::&lt;T&gt;::new_init(...)</code> for create, <code>LightAccount::&lt;T&gt;::new_mut(...)</code> for update.</li><li><code>LightDiscriminator</code> required for compressed account structs; serialization is Borsh.</li><li><code>CpiAccounts::new(...)</code> groups signer + remaining accounts for the Light CPI.</li></ul><p>Evidence: <code>light_example.txt</code> (native Rust snippet). <code>light_basics.txt</code> (dependencies and account struct requirements).</p><h3 id="_3-required-program-ids-and-accounts-are-runtime-data-not-hardcoded" tabindex="-1">3) Required program IDs and accounts are runtime data, not hardcoded <a class="header-anchor" href="#_3-required-program-ids-and-accounts-are-runtime-data-not-hardcoded" aria-label="Permalink to &quot;3) Required program IDs and accounts are runtime data, not hardcoded&quot;">​</a></h3><ul><li>The Light System Program and Account Compression Program IDs must be available to the program.</li><li>The gateway should store Light program IDs in <code>GatewayConfig</code> (already added) and validate them.</li></ul><p>Evidence: <code>light_basics.txt</code> (table listing Light System Program and Account Compression Program involvement) and <code>light_example.txt</code> (Light CPI uses remaining accounts including trees).</p><h3 id="_4-escrow-style-program-is-optional-it-depends-on-ownership-and-composition-needs" tabindex="-1">4) “Escrow-style” program is optional; it depends on ownership and composition needs <a class="header-anchor" href="#_4-escrow-style-program-is-optional-it-depends-on-ownership-and-composition-needs" aria-label="Permalink to &quot;4) “Escrow-style” program is optional; it depends on ownership and composition needs&quot;">​</a></h3><ul><li>If the gateway owns the compressed state, an extra escrow program is not required.</li><li>A separate escrow program makes sense when: <ul><li>multiple independent actors need to compose around the same compressed state,</li><li>you want a distinct authority or upgrade policy,</li><li>you want to decouple settlement from gateway logic.</li></ul></li></ul><p>Evidence: Derived from Light’s model (compressed state is program-specific via <code>LightDiscriminator</code> and program ID usage) in <code>light_example.txt</code> and typical Solana composition patterns.</p><h2 id="proposed-integration-mapped-to-xb77-gateway" tabindex="-1">Proposed integration (mapped to xb77_gateway) <a class="header-anchor" href="#proposed-integration-mapped-to-xb77-gateway" aria-label="Permalink to &quot;Proposed integration (mapped to xb77_gateway)&quot;">​</a></h2><h3 id="a-define-compressed-receipt-state" tabindex="-1">A) Define compressed receipt state <a class="header-anchor" href="#a-define-compressed-receipt-state" aria-label="Permalink to &quot;A) Define compressed receipt state&quot;">​</a></h3><p>Define a compressed struct for a receipt commitment and minimal metadata. Only use hashes/commitments to preserve privacy.</p><ul><li>Example (conceptual): <ul><li><code>owner: Pubkey</code> (gateway or auditor)</li><li><code>order_commitment: [u8; 32]</code></li><li><code>receipt_hash: [u8; 32]</code></li><li><code>orderbook_root: [u8; 32]</code></li></ul></li></ul><p>This should be a compressed account with <code>LightDiscriminator</code> and Borsh serialization. Use <code>order_commitment</code> and <code>receipt_hash</code> so no sensitive plaintext is emitted.</p><h3 id="b-update-resolveprivateorder-to-cpi-into-light" tabindex="-1">B) Update <code>ResolvePrivateOrder</code> to CPI into Light <a class="header-anchor" href="#b-update-resolveprivateorder-to-cpi-into-light" aria-label="Permalink to &quot;B) Update `ResolvePrivateOrder` to CPI into Light&quot;">​</a></h3><p>Current code already computes <code>receipt_hash = keccak(domain || order_commitment || receipt_leaf_hash)</code> and updates <code>orderbook_root</code>. To integrate Light:</p><ul><li>Accept <code>ValidityProof</code> + <code>CompressedAccountMeta</code> and <code>PackedAddressTreeInfo</code> (for create) or just <code>CompressedAccountMeta</code> (for update) in the instruction payload.</li><li>Build a <code>LightAccount</code> wrapper and call <code>LightSystemProgramCpi::new_cpi(...)</code>.</li><li>Use <code>CpiAccounts::new(signer, remaining_accounts, light_cpi_signer)</code>.</li></ul><p>Account order expectations (high-level):</p><ol><li>signer (payer)</li><li>gateway state</li><li>instructions sysvar</li><li>Light System Program</li><li>Account Compression Program</li><li>State tree account(s)</li><li>Address tree account(s)</li><li>(optional) Light noop program if used for logging</li></ol><p>The exact ordering depends on Light’s SDK API; the key is to pass the required accounts in <code>remaining_accounts</code> per the Light SDK.</p><h3 id="c-use-client-side-sdk-to-fetch-proofs-and-metas" tabindex="-1">C) Use client-side SDK to fetch proofs and metas <a class="header-anchor" href="#c-use-client-side-sdk-to-fetch-proofs-and-metas" aria-label="Permalink to &quot;C) Use client-side SDK to fetch proofs and metas&quot;">​</a></h3><p>Client (or off-chain agent) needs to provide:</p><ul><li><code>ValidityProof</code></li><li><code>CompressedAccountMeta</code></li><li>Address tree info if creating new compressed accounts</li></ul><p>Evidence: <code>light_basics.txt</code> and <code>light_example.txt</code> mention these are fetched client-side (<code>getValidityProof()</code> and account metas).</p><h2 id="open-questions-uncertainties" tabindex="-1">Open questions / uncertainties <a class="header-anchor" href="#open-questions-uncertainties" aria-label="Permalink to &quot;Open questions / uncertainties&quot;">​</a></h2><ul><li>Which exact Light program IDs and account ordering are required for the current SDK version in use (e.g., <code>light-sdk = 0.16.0</code>)? The local docs describe the concept, but not the concrete account list per instruction for a production setup.</li><li>Should receipts be a single compressed account per order or a tree of receipts per market? This impacts address derivation and index usage.</li><li>Whether to store <code>orderbook_root</code> in the compressed account or keep it in <code>GatewayConfig</code> and only anchor it with compressed receipts.</li></ul><h2 id="method-and-iterations" tabindex="-1">Method and iterations <a class="header-anchor" href="#method-and-iterations" aria-label="Permalink to &quot;Method and iterations&quot;">​</a></h2><ul><li>No external web searches due to gemini quota exhaustion.</li><li>Sources used are local files: <ul><li><code>light_basics.txt</code></li><li><code>light_example.txt</code></li></ul></li></ul><h2 id="source-list" tabindex="-1">Source list <a class="header-anchor" href="#source-list" aria-label="Permalink to &quot;Source list&quot;">​</a></h2><ul><li><code>light_basics.txt</code></li><li><code>light_example.txt</code></li></ul>',37)])])}const m=t(r,[["render",s]]);export{u as __pageData,m as default};
